200→            (import ./nix/overlays/default.nix)
201→          ]
202→          ++ nixpkgs.lib.optionals isDarwin [
203→            brew-nix.overlays.default
204→          ];
205→        };
206→    in
207→    flake-parts.lib.mkFlake { inherit inputs; } {
208→      systems = [
209→        "x86_64-linux"
210→        "aarch64-darwin"
211→      ];
212→
213→      imports = [
214→        treefmt-nix.flakeModule
215→        inputs.git-hooks.flakeModule
216→      ];
217→
218→      perSystem =
219→        {
220→          pkgs,
221→          system,
222→          config,
223→          ...
224→        }:
225→        let
226→          isDarwin = builtins.match ".*-darwin" system != null;
227→          darwinHostname = "M2-MacBook-Air";
228→          nom = "${pkgs.nix-output-monitor}/bin/nom";
229→          allPkgs = mkPkgs system;
230→        in
231→        {
232→          packages = {
233→            inherit (allPkgs)
234→              difit
235→              jj-desc
236→              keifu
237→              polycat
238→              pretty-ts-errors-markdown
239→              similarity-ts
240→              ;
241→          };
242→          apps = {
243→            build = {
244→              type = "app";
245→              program = toString (
246→                pkgs.writeShellScript "build" ''
247→                  set -e
248→                  ${
249→                    if isDarwin then
250→                      ''
251→                        echo "Building darwin configuration..."
252→                        ${nom} build ".#darwinConfigurations.${darwinHostname}.system"
253→                      ''
254→                    else
255→                      ''
256→                        HOSTNAME="$(hostname)"
257→                        echo "Building NixOS configuration for $HOSTNAME..."
258→                        ${nom} build ".#nixosConfigurations.$HOSTNAME.config.system.build.toplevel"
259→                      ''
260→                  }
261→                  echo "Build successful! Run 'nix run .#switch' to apply."
262→                ''
263→              );
264→            };
265→            switch = {
266→              type = "app";
267→              program = toString (
268→                pkgs.writeShellScript "switch" ''
269→                  set -eo pipefail
270→                  ${
271→                    if isDarwin then
272→                      ''
273→                        echo "Switching to darwin configuration..."
274→                        darwin-rebuild switch --flake ".#${darwinHostname}" |& ${nom}
275→                      ''
276→                    else
277→                      ''
278→                        HOSTNAME="$(hostname)"
279→                        echo "Switching to NixOS configuration for $HOSTNAME..."
280→                        sudo nixos-rebuild switch --flake ".#$HOSTNAME" |& ${nom}
281→                      ''
282→                  }
283→                  echo "Done!"
284→                ''
285→              );
286→            };
287→            fmt = {
288→              type = "app";
289→              program = toString (
290→                pkgs.writeShellScript "treefmt-wrapper" ''
291→                  exec ${config.treefmt.build.wrapper}/bin/treefmt "$@"
292→                ''
293→              );
294→            };
295→          };
296→
297→          treefmt = {
298→            projectRootFile = "flake.nix";
299→            programs = {
300→              nixfmt.enable = true;
301→              stylua.enable = true;
302→              shfmt.enable = true;
303→              oxfmt = {
304→                enable = true;
305→                excludes = [
