307→                  "nvim/lazy-lock.json"
308→                ];
309→              };
310→            };
311→            settings.global.excludes = [
312→              ".git/**"
313→              "*.lock"
314→            ];
315→          };
316→
317→          pre-commit = {
318→            check.enable = false;
319→            settings.hooks = {
320→              treefmt = {
321→                enable = true;
322→                package = config.treefmt.build.wrapper;
323→              };
324→              git-secrets = {
325→                enable = true;
326→                entry = "${pkgs.git-secrets}/bin/git-secrets --pre_commit_hook";
327→                language = "system";
328→                stages = [ "pre-commit" ];
329→                excludes = [ "^\.direnv/" ];
330→              };
331→            };
332→          };
333→
334→          devShells.default = pkgs.mkShell {
335→            shellHook = ''
336→              ${config.pre-commit.installationScript}
337→            '';
338→          };
339→        };
340→
341→      flake = {
342→        nixosConfigurations = {
343→          UM790-Pro = import ./nix/hosts/UM790-Pro { inherit inputs mkPkgs; };
344→          Still-Legend-x870 = import ./nix/hosts/Still-Legend-x870 { inherit inputs mkPkgs; };
345→        };
346→
